import { describe, expect, it } from 'vitest';
import { createPixelArt } from './pixelart-provider';

describe('PixelArt provider', () => {
  it('creates image models via .image and .imageModel', () => {
    const provider = createPixelArt();

    const imageModel = provider.image('pixelart-standard');
    const imageModel2 = provider.imageModel('pixelart-hd');

    expect(imageModel.provider).toBe('pixelart.image');
    expect(imageModel.modelId).toBe('pixelart-standard');
    expect(imageModel2.modelId).toBe('pixelart-hd');
    expect(imageModel.specificationVersion).toBe('v3');
  });

  it('throws NoSuchModelError for unsupported model types', () => {
    const provider = createPixelArt();

    expect(() => provider.languageModel('some-id')).toThrowError(
      'No such languageModel',
    );
    expect(() => provider.embeddingModel('some-id')).toThrowError(
      'No such embeddingModel',
    );
  });
});

